## 3. **Custom Saga Framework Hardening**

### **A. Versioned Saga State (Axon-style)**
```csharp
public abstract class Saga {
    public Guid SagaId { get; set; }
    public string MerchantId { get; set; }  // Sharding key
    public long Version { get; set; }
    public SagaStatus Status { get; set; }

    public virtual bool CanHandle(SagaEvent evt) => 
        evt.CorrelationId == SagaId && evt.MerchantId == MerchantId;
}
```

### **B. Optimistic Concurrency + Dead Letter**
```csharp
public async Task<SagaState> LoadSaga(string merchantId, Guid sagaId) {
    var streamId = SagaStreamSharding.GetShardStream(merchantId, "payment");
    var events = await eventStore.ReadStreamForwardAsync(streamId, sagaId);

    var saga = new PaymentSaga();
    foreach (var evt in events) {
        saga.Handle((dynamic)evt.Event.Data);
    }

    return new SagaState {
        Saga = saga,
        ExpectedVersion = events.Last().Event.EventNumber,
        StreamId = streamId
    };
}

public async Task SaveSaga(SagaState state, SagaEvent[] newEvents) {
    try {
        await eventStore.AppendToStreamAsync(
            state.StreamId, 
            state.ExpectedVersion, 
            newEvents.Select(e => new EventData(...))
        );
    } catch (WrongExpectedVersionException) {
        // Retry with fresh state (3 attempts)
        throw;
    } catch (Exception) {
        // Dead letter to Kafka DLQ
        await kafkaProducer.ProduceAsync("saga-dlq", deadLetterEvent);
    }
}
```

