// Cargo.toml
[lib]
crate-type = ["cdylib"]

[dependencies]
proxy-wasm = "0.2"
serde = { version = "1.0", features = ["derive"] }
serde_json = "1.0"

// src/lib.rs
use proxy_wasm::traits::*;
use serde::{Deserialize, Serialize};

#[derive(Serialize, Deserialize)]
struct HotspotAlert {
    merchant_id: String,
    latency_p95: f64,
    rate_limit: bool,
}

impl Context for SagaHotspotFilter {
    fn on_http_request_headers(&mut self, _num_headers: usize) -> Action {
        let merchant_id = self.get_http_request_header(":path")
            .unwrap_or_default()
            .split('/')
            .last()
            .unwrap_or_default()
            .to_string();

        // Telemetry V2 metrics (zero-copy)
        let p95_latency = self.get_metric(MetricType::Histogram, "saga.latency_ms.p95")
            .unwrap_or(100.0);

        if p95_latency > 200.0 {
            let alert = HotspotAlert {
                merchant_id: merchant_id.clone(),
                latency_p95: p95_latency,
                rate_limit: true,
            };

            // Async dispatch (non-blocking)
            self.dispatch_http_call(
                "velocity-control-plane:8080",
                vec!["POST", "/hotspots"],
                &serde_json::to_vec(&alert)?,
                vec![("content-type", "application/json")],
                |_response| Box::pin(async {}),
            );

            // Native rate limit descriptor
            self.set_http_rate_limit(10, Duration::from_secs(60));
        }

        Action::Continue
    }
}
```

