        redisSyncProducer.flush();

        // Warm new assignments from EventStoreDB snapshots
        assignments.forEach(this::warmFromSnapshots);
    }

    private void warmFromSnapshots(TopicPartition assignment) {
        // Bulk load recent snapshots
        eventStoreClient.readSnapshots(assignment.topic(), 100)
            .forEach(this::publishToRedisSync);
    }
}
