public class MerchantTierCache {
    private final Map<String, Tier> hotMerchants = new ConcurrentHashMap<>();

    public Tier getTier(String merchantId) {
        return hotMerchants.computeIfAbsent(merchantId, this::computeTier);
    }

    private Tier computeTier(String merchantId) {
        var velocity = velocityStream.getLatest(merchantId);
        if (velocity.rps > 1000) return Tier.VERY_HOT;  // 1% merchants
        if (velocity.rps > 100) return Tier.HOT;        // 19% merchants
        return Tier.COLD;                               // 80% merchants
    }
}
