## 🏭 **Rebalance-Proof Worker Pool**

```go
type CompensatorPool struct {
    workers      int
    pendingTasks chan compensateTask
    rebalanceCh  chan struct{}
}

type compensateTask struct {
    sagaID string
    step   int
}

func (p *CompensatorPool) worker(ctx context.Context) {
    for {
        select {
        case task := <-p.pendingTasks:
            compensateWorker(ctx, task.sagaID, task.step)

        case <-p.rebalanceCh:
            // PAUSE: Drain queue, release all leases
            p.drainAndRelease()
        }
    }
}

func (p *CompensatorPool) handleRebalance() {
    p.rebalanceCh <- struct{}{}
    // Workers pause, state machine continues (DB-only)
}
